/**
 * task_board.js
 * God-Level Vue 3 SPA for Project & Task Management.
 * Features: Full CRUD, File Drag & Drop, PBAC Security, SweetAlert2.
 */

const { createApp, ref, reactive, computed, onMounted, nextTick } = Vue;

const app = createApp({
    delimiters: ['[[', ']]'], 
    components: { draggable: window.vuedraggable },
    
    setup() {
        // --- Context Context ---
        // Dynamically get from Meta tags generated by Jinja if available
        const currentUser = ref({ 
            id: parseInt(document.querySelector('meta[name="user-id"]')?.content) || 1, 
            role: document.querySelector('meta[name="user-role"]')?.content || 'admin', 
            name: 'User' 
        });

        const isWorkerRole = (role) => ['sale', 'lead_generator', 'developer'].includes(role);

        // --- Core State ---
        const columns = ref([
            { id: 'To Do', title: 'To Do' },
            { id: 'In Progress', title: 'In Progress' },
            { id: 'Review', title: 'Review' },
            { id: 'Completed', title: 'Completed' }
        ]);

        const projects = ref([]);
        const activeProjectId = ref(''); 
        const currentTasks = ref([]);
        const allUsers = ref([]); 

        // Filters State
        const filters = reactive({ search: '', assignee_id: '', priority: '' });
        
        // Active Elements State
        const activeTask = ref(null);
        const newCommentText = ref('');
        const isDragging = ref(false);
        const isUploading = ref(false);

        // CRUD Modal Flags
        const isEditingProject = ref(false);
        const isEditingTask = ref(false);

        // Forms State
        const projectForm = reactive({ id: null, name: '', description: '', member_ids: [] });
        const teamForm = reactive({ user_ids: [] });
        const taskForm = reactive({ id: null, title: '', description: '', assignee_id: '', lead_id: null, priority: 'Medium', due_date: '' });

        // Bootstrap Modals
        let mProject, mTeam, mTask, mTaskDetail;

        // --- Computed Properties ---
        const activeProjectMembers = computed(() => {
            if (!activeProjectId.value) return [];
            const proj = projects.value.find(p => p.id === activeProjectId.value);
            return proj ? proj.members : [];
        });

        // Advanced Multi-Criteria Filter
        const filteredTasks = computed(() => {
            return currentTasks.value.filter(task => {
                const searchMatch = task.title.toLowerCase().includes(filters.search.toLowerCase());
                const assigneeMatch = !filters.assignee_id || task.assignee.id === filters.assignee_id;
                const priorityMatch = !filters.priority || task.priority === filters.priority;
                return searchMatch && assigneeMatch && priorityMatch;
            });
        });

        // --- Utility Methods ---
        const getTasks = (status) => filteredTasks.value.filter(t => t.status === status);
        const getInitials = (name) => name ? name.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase() : 'U';
        
        const formatDate = (dateStr) => {
            if (!dateStr) return '-';
            return new Date(dateStr).toLocaleString([], { month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit' });
        };
        const formatDateShort = (dateStr) => dateStr ? new Date(dateStr).toLocaleDateString([], { month: 'short', day: 'numeric' }) : '-';
        const formatTime = (dateStr) => dateStr ? new Date(dateStr).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '-';
        
        const isOverdue = (dateStr) => dateStr ? new Date(dateStr) < new Date() : false;
        
        const getStatusColor = (status) => {
            const map = { 'To Do': 'secondary', 'In Progress': 'warning', 'Review': 'primary', 'Completed': 'success' };
            return map[status] || 'dark';
        };

        // --- Security / Permissions ---
        const canDragTo = (columnId) => {
            if (currentUser.value.role === 'admin') return true;
            if (isWorkerRole(currentUser.value.role) && columnId === 'Completed') return false; 
            return true;
        };
        const canEditTask = (task) => {
            if (currentUser.value.role === 'admin') return true;
            if (task.status === 'Completed') return false; 
            return currentUser.value.id === task.assignee.id;
        };

        // ==========================================
        // DATA LOADING
        // ==========================================
        const loadGlobalData = async () => {
            try {
                const projRes = await axios.get('/api/tasks/projects');
                projects.value = projRes.data;

                if (currentUser.value.role === 'admin') {
                    const userRes = await axios.get('/api/users/');
                    allUsers.value = userRes.data.filter(u => ['admin', 'sale', 'lead_generator', 'developer'].includes(u.role));
                }
            } catch (err) { toastr.error("Failed to load workspace data."); }
        };

        const onProjectSelect = async () => {
            if (!activeProjectId.value) return;
            try {
                const res = await axios.get(`/api/tasks/?project_id=${activeProjectId.value}`);
                currentTasks.value = res.data.tasks;
            } catch (err) { toastr.error("Failed to load project tasks."); }
        };

        // ==========================================
        // PROJECT CRUD
        // ==========================================
        const openProjectModal = (editMode = false) => {
            isEditingProject.value = editMode;
            if (editMode) {
                const proj = projects.value.find(p => p.id === activeProjectId.value);
                Object.assign(projectForm, { id: proj.id, name: proj.name, description: proj.description, member_ids: [] });
            } else {
                Object.assign(projectForm, { id: null, name: '', description: '', member_ids: [] });
            }
            mProject.show();
        };

        const submitProject = async () => {
            try {
                if (isEditingProject.value) {
                    // Update existing project
                    await axios.put(`/api/tasks/projects/${projectForm.id}`, projectForm);
                    toastr.success("Project Updated");
                } else {
                    // Create new
                    const res = await axios.post('/api/tasks/projects', projectForm);
                    activeProjectId.value = res.data.id; // auto switch to new project
                    toastr.success("Project Created");
                }
                mProject.hide();
                await loadGlobalData();
                onProjectSelect();
            } catch (err) { toastr.error(err.response?.data?.detail || "Failed to save project"); }
        };

        const deleteProject = () => {
            Swal.fire({
                title: 'Delete Project?',
                text: "All associated tasks and files will be permanently destroyed.",
                icon: 'warning', showCancelButton: true, confirmButtonColor: '#DC2626', confirmButtonText: 'Yes, Destroy It!'
            }).then(async (result) => {
                if (result.isConfirmed) {
                    try {
                        await axios.delete(`/api/tasks/projects/${activeProjectId.value}`);
                        activeProjectId.value = '';
                        currentTasks.value = [];
                        toastr.success("Project Deleted");
                        loadGlobalData();
                    } catch(err) { toastr.error("Failed to delete project"); }
                }
            });
        };

        const openTeamModal = () => {
            const proj = projects.value.find(p => p.id === activeProjectId.value);
            teamForm.user_ids = proj ? proj.members.map(m => m.id) : [];
            mTeam.show();
        };

        const submitTeamMembers = async () => {
            try {
                await axios.post(`/api/tasks/projects/${activeProjectId.value}/members`, teamForm);
                toastr.success("Access List Updated");
                mTeam.hide();
                loadGlobalData();
            } catch (err) { toastr.error("Failed to update team"); }
        };

        // ==========================================
        // TASK CRUD
        // ==========================================
        const openTaskModal = (editMode = false) => {
            isEditingTask.value = editMode;
            if (editMode && activeTask.value) {
                // Ensure datetime string is formatted for local datetime input
                const dt = activeTask.value.due_date ? new Date(activeTask.value.due_date).toISOString().slice(0, 16) : '';
                Object.assign(taskForm, { 
                    id: activeTask.value.id, title: activeTask.value.title, description: activeTask.value.description, 
                    assignee_id: activeTask.value.assignee.id, lead_id: activeTask.value.lead_id, 
                    priority: activeTask.value.priority, due_date: dt 
                });
                mTaskDetail.hide(); // Hide detail modal to edit
            } else {
                Object.assign(taskForm, { id: null, title: '', description: '', assignee_id: '', lead_id: null, priority: 'Medium', due_date: '' });
            }
            mTask.show();
        };

        const submitTask = async () => {
            try {
                const payload = { ...taskForm, project_id: activeProjectId.value, due_date: new Date(taskForm.due_date).toISOString() };
                
                if (isEditingTask.value) {
                    await axios.put(`/api/tasks/${taskForm.id}`, payload);
                    toastr.success("Task Updated");
                } else {
                    await axios.post('/api/tasks/', payload);
                    toastr.success("Task Created");
                }
                
                mTask.hide();
                onProjectSelect(); 
                
                // If we edited from detail view, reopen it
                if (isEditingTask.value && activeTask.value) {
                    openTaskDetail({id: taskForm.id}); 
                }
            } catch (err) { toastr.error("Failed to save task"); }
        };

        const deleteTask = (taskId) => {
            Swal.fire({
                title: 'Delete Task?', text: "You won't be able to revert this!", icon: 'warning',
                showCancelButton: true, confirmButtonColor: '#DC2626', confirmButtonText: 'Delete'
            }).then(async (result) => {
                if (result.isConfirmed) {
                    try {
                        await axios.delete(`/api/tasks/${taskId}`);
                        toastr.success("Task Deleted");
                        mTaskDetail.hide();
                        onProjectSelect();
                    } catch(err) { toastr.error("Failed to delete task"); }
                }
            });
        };

        const onTaskDrop = (evt, newStatus) => {
            if (evt.added) {
                const task = evt.added.element;
                const oldStatus = task.status;
                if (isWorkerRole(currentUser.value.role) && newStatus === 'Completed') {
                    toastr.error("Only Admins can mark tasks as Completed.");
                    onProjectSelect(); return;
                }
                task.status = newStatus;
                axios.patch(`/api/tasks/${task.id}/status`, { status: newStatus })
                    .catch(() => { toastr.error("Failed to move"); onProjectSelect(); });
            }
        };

        // ==========================================
        // TASK DETAIL & ATTACHMENTS (Drag & Drop)
        // ==========================================
        const openTaskDetail = async (task) => {
            try {
                const res = await axios.get(`/api/tasks/${task.id}`);
                activeTask.value = res.data;
                mTaskDetail.show();
                nextTick(() => { const f = document.getElementById('commentFeed'); if(f) f.scrollTop = f.scrollHeight; });
            } catch (err) { toastr.error("Failed to load details"); }
        };

        // File Drag & Drop Handlers
        const triggerFileInput = () => document.getElementById('hiddenFileInput').click();
        
        const handleFileDrop = (e) => {
            isDragging.value = false;
            const files = e.dataTransfer.files;
            if (files.length) processFiles(files);
        };
        
        const uploadAttachment = (e) => {
            if (e.target.files.length) processFiles(e.target.files);
        };

        const processFiles = async (files) => {
            isUploading.value = true;
            for (let file of files) {
                const formData = new FormData();
                formData.append('file', file);
                formData.append('task_id', activeTask.value.id);
                try {
                    // Assuming your standard upload endpoint
                    await axios.post(`/api/tasks/${activeTask.value.id}/attachments`, formData, {
                        headers: { 'Content-Type': 'multipart/form-data' }
                    });
                } catch (err) { toastr.error(`Failed to upload ${file.name}`); }
            }
            isUploading.value = false;
            toastr.success("Files successfully uploaded to Vault");
            openTaskDetail(activeTask.value); // Refresh attachments
            onProjectSelect(); // Refresh board counters
        };

        const deleteAttachment = (attId) => {
            Swal.fire({
                title: 'Remove File?', text: "This will delete the file from the task.", icon: 'warning',
                showCancelButton: true, confirmButtonColor: '#DC2626', confirmButtonText: 'Remove'
            }).then(async (result) => {
                if (result.isConfirmed) {
                    try {
                        await axios.delete(`/api/tasks/attachments/${attId}`); // Ensure this route exists backend
                        toastr.success("File Removed");
                        openTaskDetail(activeTask.value);
                    } catch(err) { toastr.error("Failed to remove file"); }
                }
            });
        };

        // ==========================================
        // COMMUNICATION & REVIEW
        // ==========================================
        const submitComment = async () => {
            if (!newCommentText.value.trim()) return;
            try {
                await axios.post(`/api/tasks/${activeTask.value.id}/comments`, { comment: newCommentText.value });
                newCommentText.value = '';
                openTaskDetail(activeTask.value); 
            } catch (err) { toastr.error("Update failed"); }
        };

        const adminReviewTask = async (newStatus) => {
            try {
                await axios.patch(`/api/tasks/${activeTask.value.id}/status`, { status: newStatus });
                toastr.success(`Task marked as ${newStatus}`);
                mTaskDetail.hide();
                onProjectSelect();
            } catch (err) { toastr.error("Action failed"); }
        };

        // --- Init ---
        onMounted(() => {
            mProject = new bootstrap.Modal(document.getElementById('projectModal'));
            mTeam = new bootstrap.Modal(document.getElementById('manageTeamModal'));
            mTask = new bootstrap.Modal(document.getElementById('taskModal'));
            mTaskDetail = new bootstrap.Modal(document.getElementById('taskDetailModal'));
            
            loadGlobalData();
        });

        return {
            currentUser, columns, projects, activeProjectId, allUsers, activeProjectMembers,
            filters, filteredTasks, projectForm, teamForm, taskForm, activeTask, newCommentText,
            isEditingProject, isEditingTask, isDragging, isUploading,
            getTasks, getInitials, formatDate, formatDateShort, formatTime, isOverdue, getStatusColor,
            canDragTo, canEditTask, 
            onProjectSelect, openProjectModal, submitProject, deleteProject, openTeamModal, submitTeamMembers,
            openTaskModal, submitTask, deleteTask, onTaskDrop, openTaskDetail,
            triggerFileInput, handleFileDrop, uploadAttachment, deleteAttachment,
            submitComment, adminReviewTask
        };
    }
});

app.mount('#app');